func (m *Image) drawDigit(digit []byte, x, y int) {
	skf := randFloat(-maxSkew, maxSkew)
	xs := float64(x)
	r := m.dotSize / 2
	y += randInt(-r, r)
	for yo := 0; yo < fontHeight; yo++ {
		for xo := 0; xo < fontWidth; xo++ {
			if digit[yo*fontWidth+xo] != blackChar {
				continue
			}
			m.drawCircle(x+xo*m.dotSize, y+yo*m.dotSize, r, 1)
		}
		xs += skf
		x = int(xs)
	}
}
